  --font-mono: 'JetBrains Mono', monospace;
  --font-sans: 'Inter', sans-serif;

  --color-background: hsl(225 20% 3%);
  --color-foreground: hsl(210 20% 90%);

  --color-card: hsl(225 18% 5%);
  --color-card-foreground: hsl(210 20% 90%);

  --color-popover: hsl(225 18% 5%);
  --color-popover-foreground: hsl(210 20% 90%);

  --color-primary: hsl(190 100% 43%);
  --color-primary-foreground: hsl(225 20% 3%);

  --color-secondary: hsl(260 100% 65%);
  --color-secondary-foreground: hsl(210 20% 98%);

  --color-muted: hsl(225 12% 10%);
  --color-muted-foreground: hsl(215 15% 55%);

  --color-accent: hsl(190 100% 43%);
  --color-accent-foreground: hsl(225 20% 3%);

  --color-destructive: hsl(0 85% 55%);
  --color-destructive-foreground: hsl(210 40% 98%);

  --color-border: hsl(225 12% 14%);
  --color-input: hsl(225 12% 14%);
  --color-ring: hsl(190 100% 43%);

  --color-sidebar: hsl(225 20% 4%);
  --color-sidebar-border: hsl(225 12% 12%);

  --radius-sm: 0px;
  --radius-md: 0px;
  --radius-lg: 0px;
  --radius-xl: 0px;
  --radius-2xl: 0px;
}

@layer base {
  * {
    @apply border-border;
    border-radius: 0 !important;
  }
  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
}

@layer utilities {
  .chamfer {
    clip-path: polygon(8px 0, calc(100% - 8px) 0, 100% 8px, 100% 100%, calc(100% - 8px) 100%, 8px 100%, 0 100%, 0 8px);
  }
  .chamfer-sm {
    clip-path: polygon(4px 0, calc(100% - 4px) 0, 100% 4px, 100% 100%, calc(100% - 4px) 100%, 4px 100%, 0 100%, 0 4px);
  }
  .chamfer-tr {
    clip-path: polygon(0 0, calc(100% - 10px) 0, 100% 10px, 100% 100%, 0 100%);
  }
  .chamfer-tl {
    clip-path: polygon(10px 0, 100% 0, 100% 100%, 0 100%, 0 10px);
  }
  .corner-mark::before,
  .corner-mark::after {
    content: '';
    position: absolute;
    width: 6px;
    height: 6px;
    border-color: var(--color-primary);
    opacity: 0.4;
  }
  .corner-mark::before {
    top: -1px;
    left: -1px;
    border-top: 1px solid;
    border-left: 1px solid;
  }
  .corner-mark::after {
    bottom: -1px;
    right: -1px;
    border-bottom: 1px solid;
    border-right: 1px solid;
  }
  .edge-glow {
    box-shadow: 0 0 1px 0 hsl(190 100% 43% / 0.3), inset 0 0 1px 0 hsl(190 100% 43% / 0.1);
  }
  .edge-glow-strong {
    box-shadow: 0 0 8px -2px hsl(190 100% 43% / 0.4), 0 0 2px 0 hsl(190 100% 43% / 0.2);
  }
  .scan-line {
    background-image: repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      hsl(190 100% 43% / 0.015) 2px,
      hsl(190 100% 43% / 0.015) 4px
    );
  }
  .data-grid {
    background-image:
      linear-gradient(hsl(225 12% 14% / 0.5) 1px, transparent 1px),
      linear-gradient(90deg, hsl(225 12% 14% / 0.5) 1px, transparent 1px);
    background-size: 20px 20px;
  }
  .substrate {
    background-image: radial-gradient(hsl(225 12% 14% / 0.6) 1px, transparent 1px);
    background-size: 16px 16px;
  }
  .led-indicator {
    width: 6px;
    height: 6px;
    display: inline-block;
  }
  .led-on {
    background: hsl(190 100% 43%);
    box-shadow: 0 0 6px hsl(190 100% 43% / 0.6);
  }
  .led-warning {
    background: hsl(40 100% 50%);
    box-shadow: 0 0 6px hsl(40 100% 50% / 0.6);
  }
  .led-error {
    background: hsl(0 85% 55%);
    box-shadow: 0 0 6px hsl(0 85% 55% / 0.6);
  }
  .glass-panel {
    background: rgba(15, 15, 20, 0.7);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
  }
  .no-scrollbar::-webkit-scrollbar { display: none; }
  .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
}

* {
  scrollbar-width: thin;
  scrollbar-color: hsl(190 100% 43% / 0.25) transparent;
}
*::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
*::-webkit-scrollbar-track {
  background: transparent;
}
*::-webkit-scrollbar-thumb {
  background: hsl(190 100% 43% / 0.25);
  border: none;
}
*::-webkit-scrollbar-thumb:hover {
  background: hsl(190 100% 43% / 0.45);
}
*::-webkit-scrollbar-corner {
  background: transparent;
}

.react-flow__node {
  @apply font-display text-sm;
  border-radius: 0 !important;
}
.react-flow__handle {
  @apply bg-primary w-2 h-2 border-none;
  border-radius: 0 !important;
