            let dissipation = 0;

            if (type === 'power') dissipation = 0.5;
            else if (type === 'mcu') dissipation = 0.3;
            else if (type === 'comm') dissipation = 0.4;
            else if (type === 'actuator') dissipation = 1.0;
            else if (label.includes('ldo') || label.includes('regulator')) dissipation = 0.8;

