      partNumber: 'RES-10K-' + Date.now(),
      manufacturer: 'TestCorp',
      description: 'Test Resistor 10K Ohm',
      quantity: 10,
      unitPrice: '0.0500',
      supplier: 'DigiKey',
      stock: 100,
      status: 'In Stock',
